<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller;use App\Models\Subject;use Illuminate\Http\Request;use Illuminate\Validation\Rule;
class SubjectController extends Controller { public function index(){return view('admin.subjects.index',['items'=>Subject::orderBy('name')->paginate(20)]);} public function create(){return view('admin.subjects.form',['item'=>new Subject]);} public function store(Request $r){Subject::create($this->data($r));return redirect()->route('admin.subjects.index')->with('success','Mata pelajaran ditambahkan.');} public function edit(Subject $subject){return view('admin.subjects.form',['item'=>$subject]);} public function update(Request $r,Subject $subject){$subject->update($this->data($r,$subject));return redirect()->route('admin.subjects.index')->with('success','Mata pelajaran diperbarui.');} public function destroy(Subject $subject){$subject->delete();return back()->with('success','Mata pelajaran dihapus.');} private function data(Request $r,?Subject $m=null){return $r->validate(['code'=>['required','max:15',Rule::unique('subjects','code')->ignore($m?->id)],'name'=>'required|max:100','is_active'=>'nullable|boolean']);} }
